const express = require('express');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

const queryBuilder = async (filter = {}, projection = {}, sort = {}, model) => {
    try {
        const results = await model.find(filter, projection).sort(sort).exec();
        return results;
    } catch (error) {
        throw new Error('Query execution failed: ' + error.message);
    }
};

// Example Mongoose model
const User = mongoose.model('User', new mongoose.Schema({ name: String, age: Number, createdAt: Date, password: String }));

app.post('/api/users', async (req, res) => {
    const { filter, projection, sort } = req.body;
    try {
        const users = await queryBuilder(filter, projection, sort, User);
        res.json(users);
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// MongoDB connection and server start
mongoose.connect('mongodb://localhost:27017/admin-dashboard', { useNewUrlParser: true, useUnifiedTopology: true })
    .then(() => app.listen(3000, () => console.log('Server running on port 3000')))
    .catch(err => console.error(err));